#include<bits/stdc++.h>
using namespace std;
long long jc[101],n,k,a[101],s[101];
long long lowbit(long long x)
{
    return x&-x;
}
void add(long long x,long long v)
{
    for(long long i=x;i<=100;i+=lowbit(i))
    {
        s[i]+=v;
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
int main()
{
    jc[0]=1;
    for(long long i=1;i<=20;i++)
    {
        jc[i]=jc[i-1]*i;
    }
    scanf("%lld%lld",&n,&k);
    while(k--)
    {
        char op;
        cin>>op;
        if(op=='Q')
        {
            long long ans=1;
            memset(s,0,sizeof(s));
            for(long long i=1;i<=n;i++)
            {
                long long x;
                scanf("%lld",&x);
                long long tmp=x-1-query(x);
                ans+=1ll*jc[n-i]*tmp;
                add(x,1);
            }
            printf("%lld\n",ans);
        }
        else
        {
            long long x;
            scanf("%lld",&x);
            x--;
            vector<long long> v;
            for(long long i=1;i<=n;i++)
            {
                v.push_back(i);
            }
            for(long long i=n;i>=1;i--)
            {
                long long b=x/jc[i-1];
                x%=jc[i-1];
                printf("%lld ",v[b]);
                v.erase(v.begin()+b);
            }
            printf("\n");
        }
    }
    return 0;
}
